# Generate the tree for the manifest
TREE=$(find . -not -path '*/\.*' -not -name 'MANIFEST.md' | sort | awk '{
  depth = gsub(/\//, "/");
  name = $0;
  sub(/.*\//, "", name);
  indent = "";
  for (i = 1; i < depth; i++) indent = indent "  ";
  if (depth > 0) {
    # check if it is a directory
    cmd = "test -d \"" $0 "\" && echo dir || echo file"
    cmd | getline type
    close(cmd)
    if (type == "dir") {
      print indent "📁 **" name "/**"
    } else {
      print indent "📄 " name
    }
  }
}')

